request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?end ?role ?roleName ?owner ?ownerName WHERE {
  ?end vocab:ConnectorEnd_role ?role .
  ?role vocab:NamedElement_name ?roleName .
  OPTIONAL { ?role vocab:Element_owner ?owner .
             ?owner vocab:NamedElement_name ?ownerName }
}
LIMIT 50
